const query = $input.first().json.query || {};
const mode      = query['hub.mode'];
const token     = query['hub.verify_token'];
const challenge = query['hub.challenge'];
const VERIFY_TOKEN = $env.ORDERFLOW_VERIFY_TOKEN || 'mon-verify-token-secret';
if (mode === 'subscribe' && token === VERIFY_TOKEN) {
  return [{ json: { challenge, status: 200 } }];
}
return [{ json: { error: 'Forbidden', status: 403 } }];

const body = $input.first().json.body || $input.first().json;
const entry   = body?.entry?.[0];
const changes = entry?.changes?.[0]?.value;
if (!changes?.messages?.length) return [];
const message       = changes.messages[0];
const phoneNumberId = changes.metadata?.phone_number_id;
const senderPhone   = message.from;
const messageType   = message.type;
let messageText = '';
if (messageType === 'text') {
  messageText = message.text?.body?.trim() || '';
} else if (messageType === 'interactive') {
  messageText = message.interactive?.button_reply?.id || message.interactive?.list_reply?.id || '';
}
return [{ json: { phoneNumberId, senderPhone, messageText, messageType, rawMessage: message } }];

const tenant   = $('Charger config tenant').item.json[0];
const products = $('Charger produits').all().map(i => i.json);
const sessions = $('Charger session').all();
const msg      = $('Extraire le message').item.json;
const sessionData = sessions.length ? sessions[0].json : null;
const state   = sessionData?.state   || 'INITIAL';
const context = sessionData?.context || {};
const phone = msg.senderPhone;
const text  = msg.messageText.trim();

function formatCart(cart) {
  return cart.map(item => `  • ${item.name} x${item.qty} = ${(item.price * item.qty).toLocaleString('fr-FR')} FCFA`).join('\n');
}
function cartTotal(cart) {
  return cart.reduce((sum, i) => sum + i.price * i.qty, 0);
}
function buildMenu(prods) {
  return prods.map((p, i) =>
    `${i+1}. ${p.name} — ${p.price.toLocaleString('fr-FR')} FCFA${p.stock_quantity < 5 ? ' ⚠️ stock limité' : ''}`
  ).join('\n');
}
function parseSelection(text, prods) {
  const items = [];
  const pattern = /(\d+)\s*[xX×]?\s*(\d*)/g;
  let match;
  while ((match = pattern.exec(text)) !== null) {
    const idx = parseInt(match[1]) - 1;
    const qty = match[2] ? parseInt(match[2]) : 1;
    if (idx >= 0 && idx < prods.length && qty > 0) {
      const prod = prods[idx];
      items.push({ id: prod.id, name: prod.name, price: prod.price, qty });
    }
  }
  return items;
}
function checkStock(cart, prods) {
  const issues = [];
  for (const item of cart) {
    const prod = prods.find(p => p.id === item.id);
    if (prod && prod.stock_quantity < item.qty) {
      issues.push(`${item.name} (demandé: ${item.qty}, stock: ${prod.stock_quantity})`);
    }
  }
  return issues;
}

let reply = '';
let newState = state;
let newContext = { ...context };
let createOrder = null;
let stockIssues = [];

const greetings = ['bonjour', 'salut', 'hello', 'bonsoir', 'hi', 'menu', 'start', 'commencer'];
const isGreeting = greetings.some(g => text.toLowerCase().includes(g));
if (isGreeting && state !== 'INITIAL') { newState = 'INITIAL'; newContext = {}; }

switch (newState) {
  case 'INITIAL': {
    const menu = buildMenu(products);
    reply = `Bonjour ! 👋 Bienvenue chez *${tenant.name}*\n\n📋 *Notre menu :*\n${menu}\n\nTapez le numéro des plats et la quantité.\nExemple : *1 x2, 3 x1*`;
    newState = 'BROWSE_MENU';
    newContext = { cart: [] };
    break;
  }
  case 'BROWSE_MENU': {
    const parsed = parseSelection(text, products);
    if (parsed.length === 0) { reply = `Je n'ai pas compris. Tapez par exemple : *1 x2, 3 x1*`; break; }
    const cart = [...(context.cart || []), ...parsed];
    newContext = { ...newContext, cart };
    reply = `🛒 *Votre panier :*\n${formatCart(cart)}\n\n*Total : ${cartTotal(cart).toLocaleString('fr-FR')} FCFA*\n\nTapez *OK* pour continuer.`;
    newState = 'CART_REVIEW';
    break;
  }
  case 'CART_REVIEW': {
    if (text.toLowerCase() === 'ok') { reply = `Parfait 😊 Quel est votre *nom complet* ?`; newState = 'GET_NAME'; }
    else {
      const parsed = parseSelection(text, products);
      if (parsed.length > 0) {
        const cart = [...(context.cart || []), ...parsed];
        newContext = { ...newContext, cart };
        reply = `🛒 *Panier mis à jour :*\n${formatCart(cart)}\n\n*Total : ${cartTotal(cart).toLocaleString('fr-FR')} FCFA*\n\nTapez *OK* pour continuer.`;
      } else { reply = `Tapez *OK* pour valider ou envoyez des numéros pour ajouter des plats.`; }
    }
    break;
  }
  case 'GET_NAME': {
    if (text.length < 2) { reply = `Merci de saisir votre nom complet.`; break; }
    newContext = { ...newContext, customerName: text };
    reply = `Merci ${text} ! 🏠 Quelle est votre *adresse de livraison* ?`;
    newState = 'GET_ADDRESS';
    break;
  }
  case 'GET_ADDRESS': {
    if (text.length < 5) { reply = `Merci de saisir une adresse complète.`; break; }
    newContext = { ...newContext, address: text };
    reply = `📅 Pour quelle *date et heure* souhaitez-vous la livraison ?\nEx : *Demain 12h* ou *15/06 à 13h30*`;
    newState = 'GET_DATE';
    break;
  }
  case 'GET_DATE': {
    newContext = { ...newContext, deliveryDate: text };
    const cart = context.cart || [];
    const recap = `👤 *Nom :* ${context.customerName}\n🏠 *Adresse :* ${context.address}\n📅 *Livraison :* ${text}\n\n🛒 *Commande :*\n${formatCart(cart)}\n\n💰 *Total : ${cartTotal(cart).toLocaleString('fr-FR')} FCFA*`;
    reply = `*Récapitulatif :*\n\n${recap}\n\nTapez *OUI* pour confirmer ou *NON* pour annuler.`;
    newState = 'CONFIRM';
    break;
  }
  case 'CONFIRM': {
    const answer = text.toLowerCase();
    if (['oui', 'yes', 'o', 'ok', 'confirme', '✅'].includes(answer)) {
      const cart = context.cart || [];
      stockIssues = checkStock(cart, products);
      if (stockIssues.length > 0) {
        reply = `⚠️ Stock insuffisant :\n${stockIssues.map(s => `• ${s}`).join('\n')}\n\nCommande en attente de validation. Nous vous recontactons rapidement.`;
        createOrder = { ...context, cart, status: 'stock_issue' };
      } else {
        reply = `✅ *Commande confirmée !*\n\nMerci ${context.customerName}, votre commande est enregistrée pour le ${context.deliveryDate}.\n📞 En cas de question : ${tenant.whatsapp_number}`;
        createOrder = { ...context, cart, status: 'confirmed' };
      }
      newState = 'INITIAL';
      newContext = {};
    } else if (['non', 'no', 'n', 'annuler', '❌'].includes(answer)) {
      reply = `Commande annulée. À bientôt ! 👋\n\nTapez *Bonjour* pour recommencer.`;
      newState = 'INITIAL';
      newContext = {};
    } else { reply = `Tapez *OUI* pour confirmer ou *NON* pour annuler.`; }
    break;
  }
  default: {
    reply = `Bonjour ! Tapez *Menu* pour voir nos plats. 😊`;
    newState = 'INITIAL';
    newContext = {};
  }
}

return [{ json: { reply, newState, newContext, createOrder, stockIssues, tenantId: tenant.id, tenantName: tenant.name, whatsappToken: tenant.whatsapp_token, phoneNumberId: tenant.phone_number_id, senderPhone: phone, sessionExists: !!sessionData } }];

const order   = $('Créer commande en DB').item.json[0] ?? $('Créer commande en DB').item.json;
const orderId = order.id;
const cart    = $('Bot Engine').item.json.createOrder.cart;
const items   = cart.map(item => ({ order_id: orderId, product_id: item.id || null, product_name: item.name, product_price: item.price, quantity: item.qty, subtotal: item.price * item.qty }));
return [{ json: { items, orderId, livreur_id: order.livreur_id ?? null } }];
